mapper.select:
select u.user_id as userId, u.user_name as userName, u.nick_name as nickName, d.dept_name as deptName, u.phonenumber as phonenumber, r.read_time as readTime from sys_notice_read r inner join sys_user u on u.user_id = r.user_id and u.del_flag = '0' left join sys_dept d on d.dept_id = u.dept_id where r.notice_id = #{noticeId}
and ( u.user_name like concat('%', #{searchValue}, '%') or u.nick_name like concat('%', #{searchValue}, '%') )
order by r.read_time desc
